                                                   ^~~~~~~~~~
                                                   cxxrtl::debug_item
/home/tom/tools/yosys/backends/cxxrtl/cxxrtl.h:724:8: note: 'cxxrtl::debug_item' declared here
struct debug_item : ::cxxrtl_object {
       ^
/home/tom/tools/yosys/backends/cxxrtl/cxxrtl.h:146:42: warning: shift count >= width of type [-Wshift-count-overflow]
